SourceCode.Declaration:
/// <summary>
/// Class to handle the fulfillment of sales agreements within the ETGSPAIN model.
/// Inherits common logic from <c>ETGSPAINSalesPurchAgreementFulfillment</c>.
/// </summary>
class ETGSPAINSalesAgreementFulfillment extends ETGSPAINSalesPurchAgreementFulfillment
{
}

Method.Source:
/// <summary>
/// Retrieves the class description.
/// </summary>
/// <returns>A <c>ClassDescription</c> indicating the purpose of the class.</returns>
static ClassDescription description()
{
    return "@ETGSPAINLabels:ETGSPAINSalesAgreementFollowUpTmp";
}

/// <summary>
/// Enables or disables the data sources that are not required for selecting data.
/// </summary>
/// <param name="_enable">A Boolean value indicating whether the data source should be enabled.</param>
protected void enableDataSources()
{
    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        QueryBuildDataSource qbds;

        qbds = query.dataSourceTable(tableNum(PurchAgreementHeader));
        qbds.enabled(false);
        qbds.findRange(fieldNum(PurchAgreementHeader, VendAccount)).status(RangeStatus::Hidden);
        qbds.findRange(fieldNum(PurchAgreementHeader, PurchNumberSequence)).status(RangeStatus::Hidden);

        qbds = query.dataSourceTable(tableNum(SalesAgreementHeader));
        qbds.enabled(true);
        qbds.findRange(fieldNum(SalesAgreementHeader, CustAccount)).status(RangeStatus::Open);
        qbds.findRange(fieldNum(SalesAgreementHeader, SalesNumberSequence)).status(RangeStatus::Open);
    }
}

/// <summary>
/// Fills the sales agreement header information into the temporary table <c>ETGSPAINSalesPurchAgreementFollowUpTmp</c>.
/// </summary>
/// <param name="_etgSPAINSalesPurchAgreementFollowUpTmp">The temporary table to store the header data.</param>
/// <param name="_agreementHeader">The agreement header record to extract data from.</param>
/// <returns>The updated temporary table with sales agreement header data.</returns>
protected ETGSPAINSalesPurchAgreementFollowUpTmp fillSalesPurchAgreementHeader(ETGSPAINSalesPurchAgreementFollowUpTmp _etgSPAINSalesPurchAgreementFollowUpTmp, AgreementHeader _agreementHeader)
{
    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        SalesAgreementHeader    salesAgreementHeader = SalesAgreementHeader::find(_agreementHeader.RecId);

        _etgSPAINSalesPurchAgreementFollowUpTmp.AgreementId = salesAgreementHeader.SalesNumberSequence;
        _etgSPAINSalesPurchAgreementFollowUpTmp.CustVendName = strfmt("%1 - %2", salesAgreementHeader.CustAccount, salesAgreementHeader.custName());
        _etgSPAINSalesPurchAgreementFollowUpTmp.CustVendAC = salesAgreementHeader.CustAccount;
    }
    return _etgSPAINSalesPurchAgreementFollowUpTmp;
}

/// <summary>
/// Constructor method for creating an instance of <c>ETGSPAINSalesAgreementFulfillment</c>.
/// </summary>
/// <returns>An instance of <c>ETGSPAINSalesAgreementFulfillment</c>.</returns>
public static ETGSPAINSalesAgreementFulfillment construct()
{
    return new ETGSPAINSalesAgreementFulfillment();
}

/// <summary>
/// Main method for generating and returning the temporary table <c>ETGSPAINSalesPurchAgreementFollowUpTmp</c>.
/// </summary>
/// <returns>The temporary table containing the fulfillment data for the sales agreement.</returns>
public static ETGSPAINSalesPurchAgreementFollowUpTmp generateETGSPAINSalesPurchAgreementFollowUpTmp()
{
    ETGSPAINSalesAgreementFulfillment   etgSPAINSalesAgreementFulfillment;
    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
           etgSPAINSalesAgreementFulfillment = ETGSPAINSalesAgreementFulfillment::construct();

        if (etgSPAINSalesAgreementFulfillment.prompt())
        {
            etgSPAINSalesAgreementFulfillment.run();
        }
    }
    return etgSPAINSalesAgreementFulfillment.getETGSPAINSalesPurchAgreementFollowUpTmp();
}
